{
  "name": "Building Finance Manager v3.6",
  "description": "A comprehensive building financial management system for tracking management fees, parking rentals, and miscellaneous expenses with Google Sheets synchronization."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export type RecordType = '管理費' | '車位租借' | '雜支' | '初始餘額';

export interface TransactionRecord {
  id: string;
  timestamp: string;
  date: string;
  type: RecordType;
  income: number;
  expense: number;
  last3: string;
  desc: string;
  synced: boolean;
  balance?: number; // Initial balance only used for '初始餘額' type in original logic
  currentBalance?: number; // Calculated field
}

export type TabType = 'fee' | 'parking' | 'misc' | 'records';

import React, { useState, useEffect, useMemo, useCallback } from 'react';
import { 
  Building2, 
  Coins, 
  Cloud, 
  CloudOff, 
  Settings, 
  Calculator, 
  Check, 
  Car, 
  FileEdit, 
  History, 
  Plus, 
  Minus, 
  Trash2,
  X,
  Save,
  RotateCw,
  Search,
  ChevronRight
} from 'lucide-react';
import { TransactionRecord, RecordType, TabType } from './types';
import Header from './components/Header';
import BalanceCard from './components/BalanceCard';
import FeeForm from './components/FeeForm';
import ParkingForm from './components/ParkingForm';
import MiscForm from './components/MiscForm';
import RecordsTable from './components/RecordsTable';
import SettingsModal from './components/SettingsModal';
import FloatingCalculator from './components/FloatingCalculator';

const STORAGE_KEY = 'building_records_react';
const GAS_URL_KEY = 'building_gas_url_react';
const DEFAULT_GAS_URL = 'https://script.google.com/macros/s/AKfycbx7JgET8mNOAOMGvZfeuDi5YIK8fDz1pdWiv_XlYJqXkuHf9BlxODyAYXbWr5roFKAsiw/exec';

const App: React.FC = () => {
  // State
  const [records, setRecords] = useState<TransactionRecord[]>([]);
  const [activeTab, setActiveTab] = useState<TabType>('fee');
  const [gasUrl, setGasUrl] = useState<string>(localStorage.getItem(GAS_URL_KEY) || DEFAULT_GAS_URL);
  const [isSettingsOpen, setIsSettingsOpen] = useState(false);
  const [isCalcOpen, setIsCalcOpen] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [isSyncing, setIsSyncing] = useState(false);

  // Initialize data
  useEffect(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) {
      setRecords(JSON.parse(saved));
    } else {
      const initial: TransactionRecord[] = [
        {
          id: 'initial-balance-id',
          type: '初始餘額',
          date: '2025-12-31',
          desc: '上年度餘額',
          income: 0,
          expense: 0,
          balance: 378129,
          last3: '',
          timestamp: new Date('2024/12/31 23:59:59').toISOString(),
          synced: false
        }
      ];
      setRecords(initial);
      localStorage.setItem(STORAGE_KEY, JSON.stringify(initial));
    }
  }, []);

  // Save to local storage whenever records change
  useEffect(() => {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(records));
  }, [records]);

  // Save GAS URL
  useEffect(() => {
    localStorage.setItem(GAS_URL_KEY, gasUrl);
  }, [gasUrl]);

  // Derived calculations (Running Balance)
  const sortedRecords = useMemo(() => {
    const sorted = [...records].sort((a, b) => {
      const dateA = new Date(a.date).getTime();
      const dateB = new Date(b.date).getTime();
      if (dateA !== dateB) return dateA - dateB;
      return new Date(a.timestamp).getTime() - new Date(b.timestamp).getTime();
    });

    let runningBalance = 0;
    return sorted.map(r => {
      if (r.type === '初始餘額') {
        runningBalance = r.balance || 0;
      } else {
        runningBalance = runningBalance + (r.income || 0) - (r.expense || 0);
      }
      return { ...r, currentBalance: runningBalance };
    });
  }, [records]);

  const totalBalance = useMemo(() => {
    if (sortedRecords.length === 0) return 0;
    return sortedRecords[sortedRecords.length - 1].currentBalance || 0;
  }, [sortedRecords]);

  const pendingCount = useMemo(() => records.filter(r => !r.synced).length, [records]);

  // Handlers
  const addRecord = useCallback((newRecord: Omit<TransactionRecord, 'synced' | 'timestamp'>) => {
    const fullRecord: TransactionRecord = {
      ...newRecord,
      timestamp: new Date().toISOString(),
      synced: false
    };

    if (editingId) {
      setRecords(prev => prev.map(r => r.id === editingId ? fullRecord : r));
      setEditingId(null);
    } else {
      setRecords(prev => [fullRecord, ...prev]);
    }

    // Auto-trigger background sync
    setTimeout(() => syncRecords(), 500);
  }, [editingId]);

  const syncRecords = async () => {
    if (isSyncing || !gasUrl) return;
    const pending = records.filter(r => !r.synced);
    if (pending.length === 0) return;

    setIsSyncing(true);
    let updatedRecords = [...records];

    for (const record of pending) {
      try {
        const payload = { 
          action: 'update', 
          ...record, 
          // Add single quote to last3 to force Google Sheets to treat as string
          last3: record.last3 ? `'${record.last3}` : '' 
        };

        await fetch(gasUrl, {
          method: 'POST',
          mode: 'no-cors',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify(payload)
        });

        updatedRecords = updatedRecords.map(r => 
          r.id === record.id ? { ...r, synced: true } : r
        );
      } catch (error) {
        console.error('Sync error:', error);
      }
      // Small throttle
      await new Promise(res => setTimeout(res, 300));
    }

    setRecords(updatedRecords);
    setIsSyncing(false);
  };

  const handleEdit = (id: string) => {
    const record = records.find(r => r.id === id);
    if (!record) return;

    setEditingId(id);
    if (record.type === '管理費') setActiveTab('fee');
    else if (record.type === '車位租借') setActiveTab('parking');
    else if (record.type === '雜支') setActiveTab('misc');
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const cancelEdit = () => {
    setEditingId(null);
  };

  return (
    <div className="min-h-screen pb-24">
      <Header 
        isSyncing={isSyncing} 
        pendingCount={pendingCount} 
        onSync={syncRecords} 
        onSettings={() => setIsSettingsOpen(true)}
      />

      <main className="max-w-3xl mx-auto p-4 space-y-6">
        <BalanceCard total={totalBalance} />

        {editingId && (
          <div className="bg-yellow-100 border-l-4 border-yellow-500 text-yellow-700 p-4 rounded shadow-md flex justify-between items-center animate-pulse">
            <div>
              <p className="font-bold flex items-center gap-2">
                <FileEdit size={18} /> 正在修改資料
              </p>
              <p className="text-sm">請修改下方表單內容，完成後點擊「確認修改」。</p>
            </div>
            <button 
              onClick={cancelEdit}
              className="bg-white text-yellow-700 border border-yellow-500 px-3 py-1 rounded text-sm hover:bg-yellow-50 transition"
            >
              取消
            </button>
          </div>
        )}

        {/* Tab Navigation */}
        <div className="grid grid-cols-4 gap-2 bg-white p-1.5 rounded-xl shadow-sm border border-gray-100">
          {[
            { id: 'fee', label: '管理費', icon: Building2 },
            { id: 'parking', label: '車位租借', icon: Car },
            { id: 'misc', label: '雜支', icon: FileEdit },
            { id: 'records', label: '流水明細', icon: History },
          ].map(tab => (
            <button
              key={tab.id}
              onClick={() => setActiveTab(tab.id as TabType)}
              className={`flex flex-col items-center py-2.5 px-1 rounded-lg text-xs font-bold transition-all ${
                activeTab === tab.id 
                  ? 'bg-indigo-600 text-white shadow-md' 
                  : 'text-gray-500 hover:bg-gray-50'
              }`}
            >
              <tab.icon size={18} className="mb-1" />
              {tab.label}
            </button>
          ))}
        </div>

        {/* Tab Contents */}
        <div className={`transition-all duration-300 ${editingId ? 'ring-4 ring-yellow-400 ring-opacity-50' : ''}`}>
          {activeTab === 'fee' && (
            <FeeForm 
              onSubmit={addRecord} 
              editingData={editingId ? records.find(r => r.id === editingId) : undefined} 
            />
          )}
          {activeTab === 'parking' && (
            <ParkingForm 
              onSubmit={addRecord} 
              editingData={editingId ? records.find(r => r.id === editingId) : undefined} 
            />
          )}
          {activeTab === 'misc' && (
            <MiscForm 
              onSubmit={addRecord} 
              editingData={editingId ? records.find(r => r.id === editingId) : undefined} 
            />
          )}
          {activeTab === 'records' && (
            <RecordsTable 
              records={sortedRecords} 
              onEdit={handleEdit}
            />
          )}
        </div>
      </main>

      <SettingsModal 
        isOpen={isSettingsOpen} 
        onClose={() => setIsSettingsOpen(false)} 
        url={gasUrl} 
        onSave={setGasUrl} 
      />

      <FloatingCalculator 
        isOpen={isCalcOpen} 
        onToggle={() => setIsCalcOpen(!isCalcOpen)} 
      />

      {/* Persistent Mobile Calculator Trigger */}
      {!isCalcOpen && (
        <button 
          onClick={() => setIsCalcOpen(true)}
          className="fixed bottom-6 right-6 w-14 h-14 bg-indigo-900 text-white rounded-full shadow-2xl flex items-center justify-center hover:scale-110 active:scale-95 transition-all z-50 border-2 border-indigo-700"
        >
          <Calculator size={24} />
        </button>
      )}
    </div>
  );
};

export default App;

import React from 'react';
import { Building2, Cloud, CloudOff, Settings, RotateCw } from 'lucide-react';

interface HeaderProps {
  isSyncing: boolean;
  pendingCount: number;
  onSync: () => void;
  onSettings: () => void;
}

const Header: React.FC<HeaderProps> = ({ isSyncing, pendingCount, onSync, onSettings }) => {
  return (
    <header className="bg-indigo-950 text-white p-4 shadow-lg sticky top-0 z-40">
      <div className="flex justify-between items-center max-w-3xl mx-auto">
        <div className="flex items-center gap-2">
          <div className="p-2 bg-indigo-800 rounded-lg">
            <Building2 size={24} className="text-indigo-200" />
          </div>
          <h1 className="text-xl font-bold tracking-tight">大樓財務管理</h1>
        </div>

        <div className="flex items-center gap-2">
          <button 
            onClick={onSync}
            disabled={isSyncing}
            className={`flex items-center gap-2 px-3 py-1.5 rounded-lg border transition text-sm shadow-sm ${
              pendingCount > 0 
                ? 'bg-orange-600 border-orange-500 hover:bg-orange-500 animate-pulse text-white' 
                : 'bg-indigo-900 border-indigo-800 hover:bg-indigo-800 text-indigo-300'
            }`}
          >
            {isSyncing ? (
              <RotateCw size={16} className="animate-spin" />
            ) : pendingCount > 0 ? (
              <CloudOff size={16} />
            ) : (
              <Cloud size={16} />
            )}
            <span className="hidden sm:inline">
              {isSyncing ? '同步中...' : pendingCount > 0 ? `未同步 (${pendingCount})` : '已同步'}
            </span>
          </button>

          <button 
            onClick={onSettings}
            className="p-2 bg-indigo-900 border border-indigo-800 rounded-lg hover:bg-indigo-800 transition text-indigo-300"
            title="設定"
          >
            <Settings size={20} />
          </button>
        </div>
      </div>
    </header>
  );
};

export default Header;

