import React, { useState, useEffect } from 'react';
import { Check, Building2 } from 'lucide-react';
import { TransactionRecord } from '../types';

interface FeeFormProps {
  onSubmit: (record: Omit<TransactionRecord, 'synced' | 'timestamp'>) => void;
  editingData?: TransactionRecord;
}

const FeeForm: React.FC<FeeFormProps> = ({ onSubmit, editingData }) => {
  const [unit, setUnit] = useState('');
  const [period, setPeriod] = useState('115-上');
  const [date, setDate] = useState(new Date().toISOString().split('T')[0]);
  const [last3, setLast3] = useState('');
  const amount = 4800;

  useEffect(() => {
    if (editingData) {
      const parts = editingData.desc.match(/(.+) \((.+)\)/);
      if (parts) {
        setPeriod(parts[1]);
        setUnit(parts[2]);
      }
      setDate(editingData.date);
      setLast3(editingData.last3);
    }
  }, [editingData]);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!unit) return alert('請輸入戶號');

    onSubmit({
      id: editingData?.id || `fee-${Date.now()}`,
      date,
      type: '管理費',
      income: amount,
      expense: 0,
      last3,
      desc: `${period} (${unit})`,
    });

    if (!editingData) {
      setUnit('');
      setLast3('');
    }
  };

  return (
    <div className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100">
      <h2 className="text-xl font-bold text-gray-800 mb-6 flex items-center gap-2 border-b border-gray-100 pb-3">
        <Building2 className="text-indigo-600" size={24} /> 繳納管理費
      </h2>
      <form onSubmit={handleSubmit} className="space-y-4">
        <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
          <div>
            <label className="block text-sm font-semibold text-gray-700 mb-1">戶號 (如 3-2)</label>
            <input 
              type="text" 
              value={unit} 
              onChange={(e) => setUnit(e.target.value)}
              required 
              placeholder="3-2" 
              className="w-full px-4 py-3 rounded-xl border border-gray-200 focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 outline-none transition"
            />
          </div>
          <div>
            <label className="block text-sm font-semibold text-gray-700 mb-1">繳納年度</label>
            <select 
              value={period}
              onChange={(e) => setPeriod(e.target.value)}
              className="w-full px-4 py-3 rounded-xl border border-gray-200 focus:ring-2 focus:ring-indigo-500 outline-none bg-white transition"
            >
              <option value="114-上">114-上年度</option>
              <option value="114-下">114-下年度</option>
              <option value="115-上">115-上年度</option>
              <option value="115-下">115-下年度</option>
            </select>
          </div>
        </div>
        <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
          <div>
            <label className="block text-sm font-semibold text-gray-700 mb-1">繳納日期</label>
            <input 
              type="date" 
              value={date}
              onChange={(e) => setDate(e.target.value)}
              required
              className="w-full px-4 py-3 rounded-xl border border-gray-200 focus:ring-2 focus:ring-indigo-500 outline-none transition"
            />
          </div>
          <div>
            <label className="block text-sm font-semibold text-gray-700 mb-1">金額 (固定)</label>
            <div className="relative">
              <input 
                type="number" 
                value={amount} 
                readOnly 
                className="w-full px-4 py-3 rounded-xl border border-gray-100 bg-gray-50 text-gray-500 cursor-not-allowed outline-none"
              />
              <span className="absolute right-4 top-1/2 -translate-y-1/2 text-gray-400 text-sm font-bold">TWD</span>
            </div>
          </div>
        </div>
        <div>
          <label className="block text-sm font-semibold text-gray-700 mb-1">帳號後三碼</label>
          <input 
            type="text" 
            value={last3}
            onChange={(e) => setLast3(e.target.value.replace(/\D/g, '').slice(0, 5))}
            placeholder="081" 
            className="w-full px-4 py-3 rounded-xl border border-gray-200 focus:ring-2 focus:ring-indigo-500 outline-none transition"
          />
        </div>
        <button 
          type="submit" 
          className={`w-full font-bold py-4 px-4 rounded-xl shadow-lg transition-all transform active:scale-[0.98] flex items-center justify-center gap-2 ${
            editingData ? 'bg-yellow-600 hover:bg-yellow-700 text-white' : 'bg-indigo-600 hover:bg-indigo-700 text-white'
          }`}
        >
          {editingData ? <Check size={20} /> : <Check size={20} />}
          {editingData ? '確認修改' : '提交管理費'}
        </button>
      </form>
    </div>
  );
};

export default FeeForm;

import React, { useState, useEffect } from 'react';
import { Car, Check } from 'lucide-react';
import { TransactionRecord } from '../types';

interface ParkingFormProps {
  onSubmit: (record: Omit<TransactionRecord, 'synced' | 'timestamp'>) => void;
  editingData?: TransactionRecord;
}

const ParkingForm: React.FC<ParkingFormProps> = ({ onSubmit, editingData }) => {
  const [spot, setSpot] = useState('');
  const [renter, setRenter] = useState('');
  const [date, setDate] = useState(new Date().toISOString().split('T')[0]);
  const [last3, setLast3] = useState('');

  const getPrice = (s: string) => {
    if (s === '11') return 200;
    if (s) return 800;
    return 0;
  };

  useEffect(() => {
    if (editingData) {
      const parts = editingData.desc.match(/車位 (.+) \((.+)\)/);
      if (parts) {
        setSpot(parts[1]);
        setRenter(parts[2]);
      }
      setDate(editingData.date);
      setLast3(editingData.last3);
    }
  }, [editingData]);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!spot || !renter) return alert('請填寫完整資訊');

    onSubmit({
      id: editingData?.id || `parking-${Date.now()}`,
      date,
      type: '車位租借',
      income: getPrice(spot),
      expense: 0,
      last3,
      desc: `車位 ${spot} (${renter})`,
    });

    if (!editingData) {
      setSpot('');
      setRenter('');
      setLast3('');
    }
  };

  return (
    <div className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100">
      <h2 className="text-xl font-bold text-gray-800 mb-6 flex items-center gap-2 border-b border-gray-100 pb-3">
        <Car className="text-emerald-600" size={24} /> 車位租借登記
      </h2>
      <form onSubmit={handleSubmit} className="space-y-4">
        <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
          <div>
            <label className="block text-sm font-semibold text-gray-700 mb-1">車位號碼</label>
            <select 
              value={spot}
              onChange={(e) => setSpot(e.target.value)}
              className="w-full px-4 py-3 rounded-xl border border-gray-200 focus:ring-2 focus:ring-emerald-500 outline-none bg-white transition"
              required
            >
              <option value="" disabled>請選擇</option>
              <option value="8">8號</option>
              <option value="11">11號</option>
              <option value="31">31號</option>
              <option value="32">32號</option>
              <option value="33">33號</option>
            </select>
          </div>
          <div>
            <label className="block text-sm font-semibold text-gray-700 mb-1">租借人 (戶號)</label>
            <input 
              type="text" 
              value={renter}
              onChange={(e) => setRenter(e.target.value)}
              required 
              placeholder="如: 2-2" 
              className="w-full px-4 py-3 rounded-xl border border-gray-200 focus:ring-2 focus:ring-emerald-500 outline-none transition"
            />
          </div>
        </div>
        <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
          <div>
            <label className="block text-sm font-semibold text-gray-700 mb-1">匯款日期</label>
            <input 
              type="date" 
              value={date}
              onChange={(e) => setDate(e.target.value)}
              required
              className="w-full px-4 py-3 rounded-xl border border-gray-200 focus:ring-2 focus:ring-emerald-500 outline-none transition"
            />
          </div>
          <div>
            <label className="block text-sm font-semibold text-gray-700 mb-1">金額</label>
            <input 
              type="text" 
              value={spot ? `$${getPrice(spot)}` : '選擇車位後自動帶入'} 
              readOnly 
              className="w-full px-4 py-3 rounded-xl border border-gray-100 bg-gray-50 text-gray-500 outline-none"
            />
          </div>
        </div>
        <div>
          <label className="block text-sm font-semibold text-gray-700 mb-1">帳號後三碼</label>
          <input 
            type="text" 
            value={last3}
            onChange={(e) => setLast3(e.target.value.replace(/\D/g, '').slice(0, 5))}
            placeholder="081" 
            className="w-full px-4 py-3 rounded-xl border border-gray-200 focus:ring-2 focus:ring-emerald-500 outline-none transition"
          />
        </div>
        <button 
          type="submit" 
          className={`w-full font-bold py-4 px-4 rounded-xl shadow-lg transition-all transform active:scale-[0.98] flex items-center justify-center gap-2 ${
            editingData ? 'bg-yellow-600 hover:bg-yellow-700 text-white' : 'bg-emerald-600 hover:bg-emerald-700 text-white'
          }`}
        >
          <Car size={20} />
          {editingData ? '確認修改' : '登記車位'}
        </button>
      </form>
    </div>
  );
};

export default ParkingForm;

import React, { useState, useEffect } from 'react';
import { FileEdit, Check, ArrowUpRight, ArrowDownLeft } from 'lucide-react';
import { TransactionRecord } from '../types';

interface MiscFormProps {
  onSubmit: (record: Omit<TransactionRecord, 'synced' | 'timestamp'>) => void;
  editingData?: TransactionRecord;
}

const MiscForm: React.FC<MiscFormProps> = ({ onSubmit, editingData }) => {
  const [summary, setSummary] = useState('');
  const [income, setIncome] = useState<string>('');
  const [expense, setExpense] = useState<string>('');
  const [date, setDate] = useState(new Date().toISOString().split('T')[0]);

  useEffect(() => {
    if (editingData) {
      setSummary(editingData.desc);
