import React, { useState, useEffect } from 'react';
import { X, Delete, Minimize2 } from 'lucide-react';

interface FloatingCalculatorProps {
  isOpen: boolean;
  onToggle: () => void;
}

const FloatingCalculator: React.FC<FloatingCalculatorProps> = ({ isOpen, onToggle }) => {
  const [display, setDisplay] = useState('0');

  const append = (val: string) => {
    setDisplay(prev => {
      if (prev === '0' && val !== '.') return val;
      return prev + val;
    });
  };

  const clear = () => setDisplay('0');

  const del = () => {
    setDisplay(prev => prev.length > 1 ? prev.slice(0, -1) : '0');
  };

  const calculate = () => {
    try {
      // Using Function constructor for a simple, safe evaluation in this context
      // eslint-disable-next-line no-new-func
      const result = new Function(`"use strict"; return (${display})`)();
      setDisplay(String(result));
    } catch {
      setDisplay('Error');
      setTimeout(clear, 1000);
    }
  };

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (!isOpen) return;
      if (['INPUT', 'SELECT', 'TEXTAREA'].includes((e.target as HTMLElement).tagName)) return;

      const key = e.key;
      if (/[0-9.]/.test(key)) append(key);
      else if (['+', '-', '*', '/'].includes(key)) append(key);
      else if (key === 'Enter' || key === '=') { e.preventDefault(); calculate(); }
      else if (key === 'Backspace') del();
      else if (key === 'Escape') clear();
    };

    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [isOpen, display]);

  if (!isOpen) return null;

  return (
    <div className="fixed bottom-6 right-6 w-64 bg-gray-900 rounded-3xl shadow-2xl z-[100] border border-gray-800 p-4 transform animate-in slide-in-from-bottom-10 duration-300">
      <div className="flex justify-between items-center mb-3 text-white/50">
        <div className="flex items-center gap-2">
          <div className="w-3 h-3 rounded-full bg-red-500"></div>
          <div className="w-3 h-3 rounded-full bg-yellow-500"></div>
          <div className="w-3 h-3 rounded-full bg-emerald-500"></div>
        </div>
        <button onClick={onToggle} className="hover:text-white transition">
          <Minimize2 size={18} />
        </button>
      </div>

      <div className="bg-black/40 rounded-xl p-4 mb-4 text-right">
        <div className="text-emerald-400 font-mono text-2xl truncate leading-none">
          {display}
        </div>
      </div>

      <div className="grid grid-cols-4 gap-2">
        <button onClick={clear} className="col-span-2 py-3 bg-red-500/20 text-red-500 rounded-xl font-bold hover:bg-red-500 hover:text-white transition">AC</button>
        <button onClick={del} className="py-3 bg-gray-800 text-white rounded-xl flex items-center justify-center hover:bg-gray-700 transition">
          <Delete size={18} />
        </button>
        <button onClick={() => append('/')} className="py-3 bg-indigo-600 text-white rounded-xl font-bold hover:bg-indigo-500 transition">÷</button>

        {['7', '8', '9', '*'].map(key => (
          <button 
            key={key} 
            onClick={() => key === '*' ? append('*') : append(key)}
            className={`py-3 rounded-xl font-bold transition ${key === '*' ? 'bg-indigo-600 text-white hover:bg-indigo-500' : 'bg-gray-800 text-gray-300 hover:bg-gray-700'}`}
          >
            {key === '*' ? '×' : key}
          </button>
        ))}

        {['4', '5', '6', '-'].map(key => (
          <button 
            key={key} 
            onClick={() => append(key)}
            className={`py-3 rounded-xl font-bold transition ${key === '-' ? 'bg-indigo-600 text-white hover:bg-indigo-500' : 'bg-gray-800 text-gray-300 hover:bg-gray-700'}`}
          >
            {key}
          </button>
        ))}

        {['1', '2', '3', '+'].map(key => (
          <button 
            key={key} 
            onClick={() => append(key)}
            className={`py-3 rounded-xl font-bold transition ${key === '+' ? 'bg-indigo-600 text-white hover:bg-indigo-500' : 'bg-gray-800 text-gray-300 hover:bg-gray-700'}`}
          >
            {key}
          </button>
        ))}

        <button onClick={() => append('0')} className="col-span-2 py-3 bg-gray-800 text-gray-300 rounded-xl font-bold hover:bg-gray-700 transition">0</button>
        <button onClick={() => append('.')} className="py-3 bg-gray-800 text-gray-300 rounded-xl font-bold hover:bg-gray-700 transition">.</button>
        <button onClick={calculate} className="py-3 bg-indigo-500 text-white rounded-xl font-bold hover:bg-indigo-400 transition shadow-lg shadow-indigo-500/20">=</button>
      </div>
    </div>
  );
};

export default FloatingCalculator;

export type RecordType = '管理費' | '車位租借' | '雜支' | '初始餘額';

export interface TransactionRecord {
  /** 唯一的 UUID，用於識別特定交易，確保跨裝置不重複 */
  id: string;
  /** 資料產生的時間戳記，用於細節排序 */
  timestamp: string;
  /** 使用者選擇的日期 (YYYY-MM-DD) */
  date: string;
  /** 交易類型 */
  type: RecordType;
  /** 收入金額 */
  income: number;
  /** 支出金額 */
  expense: number;
  /** 帳號後三碼 (文字格式，避免 0 開頭被略過) */
  last3: string;
  /** 摘要或詳細說明 */
  desc: string;
  /** 是否已成功同步至 Google Sheet */
  synced: boolean;
  /** 僅用於初始餘額類型的原始結餘值 */
  balance?: number;
  /** 程式動態計算出的當前累計結餘 (不儲存於 LocalStorage) */
  currentBalance?: number;
}

export type TabType = 'fee' | 'parking' | 'misc' | 'records';

import React, { useState, useEffect, useMemo, useCallback } from 'react';
import { TransactionRecord, TabType } from './types';
import Header from './components/Header';
import BalanceCard from './components/BalanceCard';
import FeeForm from './components/FeeForm';
import ParkingForm from './components/ParkingForm';
import MiscForm from './components/MiscForm';
import RecordsTable from './components/RecordsTable';
import SettingsModal from './components/SettingsModal';
import FloatingCalculator from './components/FloatingCalculator';
import { FileEdit, Calculator } from 'lucide-react';

const STORAGE_KEY = 'building_records_v3_6_final';
const GAS_URL_KEY = 'building_gas_url_v3_6_final';
const DEFAULT_GAS_URL = 'https://script.google.com/macros/s/AKfycbx7JgET8mNOAOMGvZfeuDi5YIK8fDz1pdWiv_XlYJqXkuHf9BlxODyAYXbWr5roFKAsiw/exec';

const App: React.FC = () => {
  const [records, setRecords] = useState<TransactionRecord[]>([]);
  const [activeTab, setActiveTab] = useState<TabType>('fee');
  const [gasUrl, setGasUrl] = useState<string>(localStorage.getItem(GAS_URL_KEY) || DEFAULT_GAS_URL);
  const [isSettingsOpen, setIsSettingsOpen] = useState(false);
  const [isCalcOpen, setIsCalcOpen] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [isSyncing, setIsSyncing] = useState(false);

  // Initialize data and ensure every record has a unique ID
  useEffect(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) {
      try {
        const parsed: TransactionRecord[] = JSON.parse(saved);
        const sanitized = parsed.map(r => ({
          ...r,
          id: r.id || crypto.randomUUID()
        }));
        setRecords(sanitized);
      } catch (e) {
        console.error("Failed to parse local storage", e);
      }
    } else {
      const initial: TransactionRecord = {
        id: 'init-2025-balance',
        type: '初始餘額',
        date: '2025-12-31',
        desc: '上年度餘額',
        income: 0,
        expense: 0,
        balance: 378129,
        last3: '',
        timestamp: new Date('2024-12-31T23:59:59Z').toISOString(),
        synced: false
      };
      setRecords([initial]);
    }
  }, []);

  // Persistent storage
  useEffect(() => {
    if (records.length > 0) {
      localStorage.setItem(STORAGE_KEY, JSON.stringify(records));
    }
  }, [records]);

  // Balance Calculation Core
  // Ensures strictly correct running balance based on Date -> Timestamp sorting
  const sortedRecords = useMemo(() => {
    const sorted = [...records].sort((a, b) => {
      const dateDiff = new Date(a.date).getTime() - new Date(b.date).getTime();
      if (dateDiff !== 0) return dateDiff;
      return new Date(a.timestamp).getTime() - new Date(b.timestamp).getTime();
    });

    let runningBalance = 0;
    return sorted.map(r => {
      const inc = Number(r.income) || 0;
      const exp = Number(r.expense) || 0;

      if (r.type === '初始餘額') {
        runningBalance = Number(r.balance) || 0;
      } else {
        runningBalance = runningBalance + inc - exp;
      }
      return { ...r, currentBalance: runningBalance };
    });
  }, [records]);

  const totalBalance = useMemo(() => {
    if (sortedRecords.length === 0) return 0;
    return sortedRecords[sortedRecords.length - 1].currentBalance || 0;
  }, [sortedRecords]);

  const pendingCount = useMemo(() => records.filter(r => !r.synced).length, [records]);

  const syncRecords = async () => {
    if (isSyncing || !gasUrl) return;
    const pending = records.filter(r => !r.synced);
    if (pending.length === 0) return;

    setIsSyncing(true);
    let updatedList = [...records];

    for (const record of pending) {
      try {
        const payload = { 
          action: 'upsert', // Using upsert with ID to prevent duplicates
          ...record, 
          last3: record.last3 ? `'${record.last3}` : '' 
        };

        await fetch(gasUrl, {
          method: 'POST',
          mode: 'no-cors',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify(payload)
        });

        updatedList = updatedList.map(r => 
          r.id === record.id ? { ...r, synced: true } : r
        );
      } catch (error) {
        console.error('Sync failed for record:', record.id, error);
      }
      await new Promise(res => setTimeout(res, 400));
    }

    setRecords(updatedList);
    setIsSyncing(false);
  };

  const addOrUpdateRecord = useCallback((data: Omit<TransactionRecord, 'synced' | 'timestamp'>) => {
    const isEdit = !!editingId;
    const now = new Date().toISOString();

    if (isEdit) {
      setRecords(prev => prev.map(r => 
        r.id === editingId 
          ? { ...r, ...data, synced: false, timestamp: now } 
          : r
      ));
      setEditingId(null);
    } else {
      const newFullRecord: TransactionRecord = {
        ...data,
        id: data.id || crypto.randomUUID(),
        timestamp: now,
        synced: false
      };
      setRecords(prev => [...prev, newFullRecord]);
    }

    // Auto sync attempt
    setTimeout(() => syncRecords(), 1000);
  }, [editingId, gasUrl, records]);

  const handleEdit = (id: string) => {
    const record = records.find(r => r.id === id);
    if (!record) return;
    setEditingId(id);
    if (record.type === '管理費') setActiveTab('fee');
    else if (record.type === '車位租借') setActiveTab('parking');
    else if (record.type === '雜支') setActiveTab('misc');
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const cancelEdit = () => setEditingId(null);

  const saveGasUrl = (url: string) => {
    setGasUrl(url);
    localStorage.setItem(GAS_URL_KEY, url);
  };

  return (
    <div className="min-h-screen pb-24">
      <Header 
        isSyncing={isSyncing} 
        pendingCount={pendingCount} 
        onSync={syncRecords} 
        onSettings={() => setIsSettingsOpen(true)}
      />

      <main className="max-w-3xl mx-auto p-4 space-y-6">
        <BalanceCard total={totalBalance} />

