            { id: 'parking', label: '車位租借' },
            { id: 'misc', label: '雜支' },
            { id: 'records', label: '明細' },
          ].map(tab => (
            <button
              key={tab.id}
              onClick={() => { setActiveTab(tab.id as TabType); cancelEdit(); }}
              className={`py-2.5 rounded-lg text-xs font-bold transition-all ${
                activeTab === tab.id 
                  ? 'bg-indigo-600 text-white shadow-md' 
                  : 'text-gray-500 hover:bg-gray-50'
              }`}
            >
              {tab.label}
            </button>
          ))}
        </div>

        <div className="transition-all duration-300">
          {activeTab === 'fee' && (
            <FeeForm 
              onSubmit={addOrUpdateRecord} 
              editingData={editingId ? records.find(r => r.id === editingId) : undefined} 
            />
          )}
          {activeTab === 'parking' && (
            <ParkingForm 
              onSubmit={addOrUpdateRecord} 
              editingData={editingId ? records.find(r => r.id === editingId) : undefined} 
            />
          )}
          {activeTab === 'misc' && (
            <MiscForm 
              onSubmit={addOrUpdateRecord} 
              editingData={editingId ? records.find(r => r.id === editingId) : undefined} 
            />
          )}
          {activeTab === 'records' && (
            <RecordsTable 
              records={sortedRecords} 
              onEdit={handleEdit}
            />
          )}
        </div>
      </main>

      <SettingsModal 
        isOpen={isSettingsOpen} 
        onClose={() => setIsSettingsOpen(false)} 
        url={gasUrl} 
        onSave={saveGasUrl} 
      />

      <FloatingCalculator 
        isOpen={isCalcOpen} 
        onToggle={() => setIsCalcOpen(!isCalcOpen)} 
      />

      {!isCalcOpen && (
        <button 
          onClick={() => setIsCalcOpen(true)}
          className="fixed bottom-6 right-6 w-14 h-14 bg-indigo-900 text-white rounded-full shadow-2xl flex items-center justify-center hover:scale-110 active:scale-95 transition-all z-50 border-2 border-indigo-700"
        >
          <Calculator size={24} />
        </button>
      )}
    </div>
  );
};

