    id: string;
    timestamp: string;
    date: string;
    type: RecordType;
    income: number;
    expense: number;
    last3: string;
    desc: string;
    synced: boolean;
    balance?: number; // Only for initial balance
    currentBalance?: number; // Computed at runtime
}

// --- Constants & Config ---
