const FeeForm = ({ onSubmit, editingData }: any) => {
    const [unit, setUnit] = useState('');
    const [period, setPeriod] = useState('115-上');
    const [date, setDate] = useState(new Date().toISOString().split('T')[0]);
    const [last3, setLast3] = useState('');
    const amount = 4800;

    useEffect(() => {
        if (editingData) {
            const parts = editingData.desc.match(/(.+) \((.+)\)/);
            if (parts) { setPeriod(parts[1]); setUnit(parts[2]); }
            setDate(editingData.date); setLast3(editingData.last3);
        }
    }, [editingData]);

    const handleSubmit = (e: React.FormEvent) => {
        e.preventDefault();
        if (!unit) return alert('請輸入戶號');
        onSubmit({ id: editingData?.id || generateId(), date, type: '管理費', income: amount, expense: 0, last3, desc: `${period} (${unit})` });
        if (!editingData) { setUnit(''); setLast3(''); }
    };

    return (
        <div className="bg-white p-7 rounded-3xl shadow-sm border border-gray-100">
            <h2 className="text-xl font-black text-gray-800 mb-6 flex items-center gap-3 border-b border-gray-100 pb-4">
                <Building2 className="text-indigo-600" size={26} /> 繳納管理費
            </h2>
            <form onSubmit={handleSubmit} className="space-y-5">
                <div className="grid grid-cols-1 sm:grid-cols-2 gap-5">
                    <div>
                        <label className="block text-sm font-bold text-gray-600 mb-2">戶號 (例如 3-2)</label>
                        <input type="text" value={unit} onChange={(e) => setUnit(e.target.value)} required placeholder="3-2" className="w-full px-4 py-3.5 rounded-2xl border border-gray-200 focus:ring-4 focus:ring-indigo-500/10 focus:border-indigo-500 outline-none transition-all" />
                    </div>
                    <div>
                        <label className="block text-sm font-bold text-gray-600 mb-2">繳納年度</label>
                        <select value={period} onChange={(e) => setPeriod(e.target.value)} className="w-full px-4 py-3.5 rounded-2xl border border-gray-200 focus:ring-4 focus:ring-indigo-500/10 focus:border-indigo-500 outline-none bg-white transition-all appearance-none cursor-pointer">
                            <option value="114-上">114-上年度</option><option value="114-下">114-下年度</option><option value="115-上">115-上年度</option><option value="115-下">115-下年度</option>
                        </select>
                    </div>
                </div>
                <div className="grid grid-cols-1 sm:grid-cols-2 gap-5">
                    <div>
                        <label className="block text-sm font-bold text-gray-600 mb-2">匯款日期</label>
                        <input type="date" value={date} onChange={(e) => setDate(e.target.value)} required className="w-full px-4 py-3.5 rounded-2xl border border-gray-200 focus:ring-4 focus:ring-indigo-500/10 focus:border-indigo-500 outline-none transition-all" />
                    </div>
                    <div>
                        <label className="block text-sm font-bold text-gray-600 mb-2">金額 (固定)</label>
                        <div className="relative">
                            <span className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400 font-bold">$</span>
                            <input type="number" value={amount} readOnly className="w-full pl-8 pr-4 py-3.5 rounded-2xl border border-gray-100 bg-gray-50 text-gray-500 cursor-not-allowed font-bold" />
                        </div>
                    </div>
                </div>
                <div>
                    <label className="block text-sm font-bold text-gray-600 mb-2">帳號後三碼</label>
                    <input type="text" value={last3} onChange={(e) => setLast3(e.target.value.replace(/\D/g, '').slice(0, 5))} placeholder="081" className="w-full px-4 py-3.5 rounded-2xl border border-gray-200 focus:ring-4 focus:ring-indigo-500/10 focus:border-indigo-500 outline-none transition-all font-mono" />
                </div>
                <button type="submit" className={`w-full font-black py-4.5 rounded-2xl shadow-xl transition-all transform active:scale-[0.97] ${editingData ? 'bg-amber-500 shadow-amber-200' : 'bg-indigo-600 shadow-indigo-200'} text-white text-lg`}>
                    {editingData ? '確認更新數據' : '確認提交紀錄'}
                </button>
            </form>
        </div>
    );
};

