const FloatingCalculator = ({ isOpen, onToggle }: any) => {
    const [display, setDisplay] = useState('0');
    const append = (val: string) => setDisplay(prev => (prev === '0' && val !== '.' ? val : prev + val));
    const clear = () => setDisplay('0');
    const del = () => setDisplay(prev => (prev.length > 1 ? prev.slice(0, -1) : '0'));
    const calculate = () => { try { setDisplay(String(new Function(`"use strict"; return (${display})`)())); } catch { setDisplay('Error'); setTimeout(clear, 1000); } };

    useEffect(() => {
        const handleKey = (e: KeyboardEvent) => {
            if (!isOpen || ['INPUT', 'SELECT', 'TEXTAREA'].includes((e.target as HTMLElement).tagName)) return;
            if (/[0-9.]/.test(e.key)) append(e.key);
            else if (['+', '-', '*', '/'].includes(e.key)) append(e.key);
            else if (e.key === 'Enter' || e.key === '=') { e.preventDefault(); calculate(); }
            else if (e.key === 'Backspace') del();
            else if (e.key === 'Escape') clear();
        };
        window.addEventListener('keydown', handleKey);
        return () => window.removeEventListener('keydown', handleKey);
    }, [isOpen, display]);

    if (!isOpen) return null;
    return (
        <div className="fixed bottom-6 right-6 w-64 bg-gray-900 rounded-[2rem] shadow-2xl z-[100] border border-gray-800 p-5 animate-in slide-in-from-bottom-10 duration-300 glass-effect ring-1 ring-white/10">
            <div className="flex justify-between items-center mb-4 text-white/50">
                <div className="flex gap-2.5">
                    <div className="w-3 h-3 rounded-full bg-red-500 shadow-lg shadow-red-500/50"></div>
                    <div className="w-3 h-3 rounded-full bg-yellow-500 shadow-lg shadow-yellow-500/50"></div>
                    <div className="w-3 h-3 rounded-full bg-emerald-500 shadow-lg shadow-emerald-500/50"></div>
                </div>
                <button onClick={onToggle} className="hover:text-white transition-colors"><Minimize2 size={18} /></button>
            </div>
            <div className="bg-black/40 rounded-2xl p-5 mb-5 text-right">
                <div className="text-emerald-400 font-mono text-3xl font-black truncate leading-none drop-shadow-[0_0_10px_rgba(52,211,153,0.3)]">{display}</div>
            </div>
            <div className="grid grid-cols-4 gap-3">
                <button onClick={clear} className="col-span-2 py-3.5 bg-red-500/20 text-red-500 rounded-2xl font-black text-sm active:scale-90 transition-transform">AC</button>
                <button onClick={del} className="py-3.5 bg-gray-800 text-white rounded-2xl flex justify-center active:scale-90 transition-transform"><X size={18} /></button>
                <button onClick={() => append('/')} className="py-3.5 bg-indigo-600 text-white rounded-2xl font-black active:scale-90 transition-transform">÷</button>
                {['7', '8', '9', '*', '4', '5', '6', '-', '1', '2', '3', '+'].map(k => (
                    <button key={k} onClick={() => append(k)} className={`py-3.5 rounded-2xl font-black active:scale-90 transition-transform ${['*', '-', '+'].includes(k) ? 'bg-indigo-600 text-white' : 'bg-gray-800 text-gray-300'}`}>{k === '*' ? '×' : k}</button>
                ))}
                <button onClick={() => append('0')} className="col-span-2 py-3.5 bg-gray-800 text-gray-300 rounded-2xl font-black active:scale-90 transition-transform">0</button>
                <button onClick={() => append('.')} className="py-3.5 bg-gray-800 text-gray-300 rounded-2xl font-black active:scale-90 transition-transform">.</button>
                <button onClick={calculate} className="py-3.5 bg-indigo-500 text-white rounded-2xl font-black shadow-lg shadow-indigo-500/30 active:scale-95 transition-all text-xl">=</button>
            </div>
        </div>
    );
};

