const App = () => {
    const [records, setRecords] = useState<TransactionRecord[]>([]);
    const [activeTab, setActiveTab] = useState('fee');
    const [gasUrl, setGasUrl] = useState(localStorage.getItem(GAS_URL_KEY) || DEFAULT_GAS_URL);
    const [isSettingsOpen, setIsSettingsOpen] = useState(false);
    const [isCalcOpen, setIsCalcOpen] = useState(false);
    const [editingId, setEditingId] = useState<string | null>(null);
    const [isSyncing, setIsSyncing] = useState(false);

    useEffect(() => {
        const saved = localStorage.getItem(STORAGE_KEY);
        if (saved) {
            try { 
                const parsed = JSON.parse(saved);
                const sanitized = parsed.map((r: any) => ({ ...r, id: r.id || generateId() }));
                setRecords(sanitized); 
            } catch { setRecords([]); }
        } else {
            const initial: TransactionRecord = { 
                id: 'init-balance-fixed', 
                type: '初始餘額', 
                date: '2024-12-31', 
                desc: '113年度結轉餘額', 
                income: 0, 
                expense: 0, 
                balance: 378129, 
                last3: '', 
                timestamp: new Date('2024-12-31T23:59:59Z').toISOString(), 
                synced: false 
            };
            setRecords([initial]);
        }
    }, []);

    useEffect(() => { 
        if (records.length > 0) localStorage.setItem(STORAGE_KEY, JSON.stringify(records)); 
    }, [records]);

    const sortedRecords = useMemo(() => {
        const sorted = [...records].sort((a, b) => {
            const dDiff = new Date(a.date).getTime() - new Date(b.date).getTime();
            return dDiff !== 0 ? dDiff : new Date(a.timestamp).getTime() - new Date(b.timestamp).getTime();
        });

        let bal = 0;
        return sorted.map(r => {
            if (r.type === '初始餘額') {
                bal = Number(r.balance) || 0;
            } else {
                const inc = Number(r.income) || 0;
                const exp = Number(r.expense) || 0;
                bal = bal + inc - exp;
            }
            return { ...r, currentBalance: bal };
        });
    }, [records]);

    const totalBalance = useMemo(() => sortedRecords.length ? sortedRecords[sortedRecords.length - 1].currentBalance! : 0, [sortedRecords]);
    const pendingCount = useMemo(() => records.filter(r => !r.synced).length, [records]);

    const syncRecords = async () => {
        if (isSyncing || !gasUrl) return;
        const pending = records.filter(r => !r.synced);
        if (!pending.length) {
            alert('目前數據已是最新狀態，無需同步。');
            return;
        }

        setIsSyncing(true);
        let currentList = [...records];

        for (const r of pending) {
            try {
                const payload = { 
                    action: 'upsert', 
                    ...r, 
                    last3: r.last3 ? `'${r.last3}` : '' 
                };

                await fetch(gasUrl, { 
                    method: 'POST', 
                    mode: 'no-cors', 
                    body: JSON.stringify(payload)
                });

                currentList = currentList.map(item => item.id === r.id ? { ...item, synced: true } : item);
            } catch (e) { console.error('同步失敗:', e); }
            await new Promise(res => setTimeout(res, 350));
        }
        setRecords(currentList); 
        setIsSyncing(false);
    };

    const addOrUpdate = useCallback((data: any) => {
        const now = new Date().toISOString();
        if (editingId) {
            setRecords(prev => prev.map(r => r.id === editingId ? { ...r, ...data, synced: false, timestamp: r.timestamp } : r));
            setEditingId(null);
        } else {
            setRecords(prev => [...prev, { ...data, timestamp: now, synced: false }]);
        }
        setTimeout(syncRecords, 1500);
    }, [editingId, gasUrl, records]);

    const handleDelete = (id: string) => {
        if (window.confirm('確定要永久刪除此筆紀錄嗎？此操作無法撤銷。')) {
            const newRecords = records.filter(r => r.id !== id);
            setRecords(newRecords);
            alert('已從本地移除。請點擊上方同步按鈕以確保雲端數據也同步刪除。');
        }
    };

    const handleEdit = (id: string) => {
        const r = records.find(item => item.id === id);
        if (!r) return;
        setEditingId(id);
        if (r.type === '管理費') setActiveTab('fee');
        else if (r.type === '車位租借') setActiveTab('parking');
        else setActiveTab('misc');
        window.scrollTo({ top: 0, behavior: 'smooth' });
    };

    const cancelEdit = () => setEditingId(null);

    return (
        <div className="min-h-screen pb-28">
            <Header isSyncing={isSyncing} pendingCount={pendingCount} onSync={syncRecords} onSettings={() => setIsSettingsOpen(true)} />

            <main className="max-w-3xl mx-auto p-4 space-y-7 mt-2">
                <BalanceCard total={totalBalance} />

                {editingId && (
                    <div className="bg-amber-50 border-2 border-amber-200 text-amber-800 p-5 rounded-3xl shadow-lg flex justify-between items-center animate-in slide-in-from-top-4 duration-500">
                        <div className="flex items-center gap-4">
                            <div className="p-2 bg-amber-100 rounded-xl"><FileEdit size={22} className="text-amber-600" /></div>
                            <div>
                                <p className="font-black text-lg">模式切換：正在編輯歷史紀錄</p>
                                <p className="text-xs font-bold opacity-70 italic tracking-wide">注意：修改日期可能會影響到後續所有結餘的顯示順序。</p>
                            </div>
                        </div>
                        <button onClick={cancelEdit} className="bg-white border-2 border-amber-200 px-5 py-2 rounded-2xl text-sm font-black hover:bg-amber-100 transition-colors shadow-sm">退出編輯</button>
                    </div>
                )}

                <div className="grid grid-cols-4 gap-2.5 bg-white p-2 rounded-3xl shadow-sm border border-gray-100 sticky top-24 z-30 glass-effect ring-1 ring-gray-100">
                    {['fee', 'parking', 'misc', 'records'].map(tab => (
                        <button 
                            key={tab} 
                            onClick={() => { setActiveTab(tab); cancelEdit(); }} 
                            className={`py-3.5 rounded-2xl text-sm font-black transition-all transform active:scale-95 ${activeTab === tab ? 'bg-indigo-600 text-white shadow-xl shadow-indigo-100' : 'text-gray-400 hover:bg-gray-50'}`}
                        >
                            {tab === 'fee' ? '管理費' : tab === 'parking' ? '租借' : tab === 'misc' ? '雜支' : '明細'}
                        </button>
                    ))}
                </div>

                <div className="tab-transition">
                    {activeTab === 'fee' && <FeeForm onSubmit={addOrUpdate} editingData={records.find(r => r.id === editingId)} />}
                    {activeTab === 'parking' && <ParkingForm onSubmit={addOrUpdate} editingData={records.find(r => r.id === editingId)} />}
                    {activeTab === 'misc' && <MiscForm onSubmit={addOrUpdate} editingData={records.find(r => r.id === editingId)} />}
                    {activeTab === 'records' && <RecordsTable records={sortedRecords} onEdit={handleEdit} onDelete={handleDelete} />}
                </div>
            </main>

            <SettingsModal isOpen={isSettingsOpen} onClose={() => setIsSettingsOpen(false)} url={gasUrl} onSave={(url: string) => { setGasUrl(url); localStorage.setItem(GAS_URL_KEY, url); }} />
            <FloatingCalculator isOpen={isCalcOpen} onToggle={() => setIsCalcOpen(!isCalcOpen)} />

            {!isCalcOpen && (
                <button 
                    onClick={() => setIsCalcOpen(true)} 
                    className="fixed bottom-8 right-8 w-16 h-16 bg-indigo-900 text-white rounded-[1.75rem] shadow-2xl flex items-center justify-center hover:scale-110 active:scale-95 transition-all z-50 border-2 border-indigo-700/50 group"
                >
                    <Calculator size={28} className="group-hover:rotate-12 transition-transform" />
                </button>
            )}
        </div>
    );
};

const root = ReactDOM.createRoot(document.getElementById('root')!);
root.render(<App />);
